### Description

I'm not sure if it's a bug. If I use a signal inside the `transform` method of a `pipe`, since that method is used in the template, shouldn't the template update when the signal changes?

The current behavior is: the template updates only if the pipe argument changes.

```ts
import {
  Component,
  Pipe,
  PipeTransform,
  Service,
  signal,
  inject,
  ChangeDetectionStrategy,
  provideZonelessChangeDetection,
} from '@angular/core';
import { bootstrapApplication } from '@angular/platform-browser';

@Service()
export class TestService {
  public readonly test = signal(0);

  constructor() {
    setInterval(() => {
      this.test.update((value) => value + 1);
    }, 1000);
  }
}

@Pipe({
  name: 'test',
})
export class TestPipe implements PipeTransform {
  private readonly testService = inject(TestService);
  transform(value: number): number {
    return this.testService.test() * value;
  }
}

@Component({
  selector: 'app-root',
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    {{ testService.test() }}
    <button (click)="counter.update(value => value +1)">{{ counter() | test}}</button>
  `,
  imports: [TestPipe],
})
export class App {
  protected readonly testService = inject(TestService);
  protected readonly counter = signal(1);
}

bootstrapApplication(App, {
  providers: [provideZonelessChangeDetection()],
});
```

