`ts
import { booleanAttribute, Component, input, model, output } from '@angular/core';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { FormValueControl, ValidationError, WithOptionalFieldTree } from '@angular/forms/signals';

@Component({
  selector: 'jp-input-text',
  standalone: true,
  template: `
  <mat-form-field>

    <mat-label>{{ label() }}</mat-label>

        <input  matInput type="text" 
                    [value]="value()" 
                    (input)="value.set($event.target.value)"
                    (blur)="touch.emit()" 
                    [attr.maxlength]="maxLength()">

        @if(showMaxLength() && maxLength())
        {
            <mat-hint align="end">{{ value().length }} / {{ maxLength() }}</mat-hint>
        }

        @if (invalid() && touched()) 
        {
            @for (error of errors(); track error.kind) 
            {
                @if(error.kind == "maxLength")
                {
                    <mat-error>max length</mat-error>
                }
               <!-- errors... -->
            }
        }
    </mat-form-field>
  `,
  imports: [MatFormFieldModule, MatInputModule]
})
export class InputText implements FormValueControl<string>
{
    value = model.required<string>();
    touch = output<void>();

    maxLength = input<number>();

    label = input<string>();

    showMaxLength = input(false, { transform: booleanAttribute });

    readonly errors = input<readonly WithOptionalFieldTree<ValidationError>[]>([]);
    readonly invalid = input<boolean>(false);
    readonly touched = input<boolean>(false);
}

// Parent
import { Component, signal } from '@angular/core';
import { form, FormField, maxLength, required } from '@angular/forms/signals';
import { InputText } from 'angular-mat-input';

@Component({
  selector: 'app-root',
  imports: [InputText, FormField],
  template: `<jp-input-text label="Nom" [formField]="_form.nom" showMaxLength />`,
  styleUrl: './app.css'
})
export class App
{
  protected signalPasForm = signal({
    nom: "test test"
  });

  _form = form(this.signalPasForm, x => {
      maxLength(x.nom, 1),
      required(x.nom)
  });
}`


